function fallbackFact(sub, top) {
  const t = top.replace(/-/g, ' ');
  return {
    n: `This module investigates advanced concepts within ${t}. The curriculum delves into evaluating deep patterns and structured frameworks crucial for mastery in ${sub}, challenging you to think beyond fundamental semantics.`,
    q: `Which skill is critically enhanced by analyzing ${t}?`,
    o: [`Advanced analytical thinking`, `Memorizing random words`, `Decreasing cognitive load`, `Ignoring previous rules`],
    a: `Advanced analytical thinking`
  };
}

let code = "const courses = {\\n";

Object.keys(subjectsMap).forEach((sub, subIdx) => {
  code += "  '" + sub + "': {\\n";
  subjectsMap[sub].forEach((topic, idx) => {
    let details = (data[sub] && data[sub][topic]) ? data[sub][topic] : fallbackFact(sub, topic);
    let isLast = idx === subjectsMap[sub].length - 1;
    let videoUrl = customVideoMap[sub + "-" + topic] || defaultVideos[sub];
    
    // Safety escape for quotes
    let n = details.n.replace(/"/g, '\\\\\"');
    let q = details.q.replace(/"/g, '\\\\\"');
    let a = details.a.replace(/"/g, '\\\\\"');
    let formattedTopic = topic.replace(/-/g, ' ').replace(/\\b\\w/g, c=>c.toUpperCase());

    code += "    '" + topic + "': {\\n" +
            "      title: '" + formattedTopic + " Masterclass',\\n" +
            "      videoUrl: '" + videoUrl + "',\\n" +
            "      notes: \\\"" + n + "\\\",\\n" +
            "      practiceSum: \\\"" + q + "\\\",\\n" +
            "      practiceOptions: " + JSON.stringify(details.o) + ",\\n" +
            "      practiceAnswer: \\\"" + a + "\\\"\\n" +
            "    }" + (isLast ? "" : ",") + "\\n";
  });
  code += "  }" + (subIdx === Object.keys(subjectsMap).length - 1 ? "" : ",") + "\\n";
});

code += "};\\n\\nmodule.exports = courses;\\n";

fs.writeFileSync('data/courseContent.js', code);
console.log('courseContent.js heavily customized with intense logic questions!');
